sql:
SELECT COUNT(*) 
FROM case_symptoms 
WHERE symptom_value = 'Yes' AND symptom_severity > 2;

SELECT hospital_name, icu_beds
FROM hospitals
WHERE icu_beds > 1000;

SELECT hospital_name, total_beds 
FROM hospitals 
WHERE icu_beds > (SELECT AVG(icu_beds) FROM hospitals);

SELECT contact_number, email, first_name, last_name 
FROM patients 
WHERE patient_id = '1';

external_knowledge:
- 'oceans of healthcare' refers to hospitals with a significant number of beds;
- 'waves' metaphorically represent the total number of beds in a hospital;
- 'harbor' symbolizes ICU beds, places where critically ill patients receive intensive medical care;
- The question seeks to highlight hospitals with substantial capacities and ICU facilities, ranking them by their overall bed count.

sql:
SELECT email
FROM epidemiologists
WHERE epidemiologist_id = '1';

SELECT emergency_contact_number
FROM patients
WHERE patient_id = '1';

SELECT patients.first_name AS patient_first_name, epidemiologists.first_name AS epidemiologist_first_name
FROM patients
CROSS JOIN epidemiologists;

SELECT *
FROM patients
WHERE date_of_birth >= DATE('now', '-4 years');

SELECT patient_id, infection_date
FROM infectors
WHERE infection_date BETWEEN '2022-01-01' AND '2022-12-31';

external_knowledge:
- 'shadows' refers to the infectors;
- 'cast darkness' metaphorically means infecting;
- 'public health domain' refers to users with the role 'public_health_official';
- 'ensnared' refers to the patients infected;
- 'plague' refers to the disease;
- 'shadowy realm with the code '1'' refers to the infection location '1'.
